import 'dart:convert'; import 'package:shared_preferences/shared_preferences.dart'; mixin PersistenceMixin { Future<void> saveString(String key, String value) async { final prefs = await SharedPreferences.getInstance(); await prefs.setString(key, value); } Future<String?> loadString(String key) async { final prefs = await SharedPreferences.getInstance(); return prefs.getString(key); } Future<void> saveJson(String key, Map<String, dynamic> data) => saveString(key, jsonEncode(data)); Future<Map<String, dynamic>?> loadJson(String key) async { final s = await loadString(key); return s != null ? Map<String, dynamic>.from(jsonDecode(s)) : null; } Future<void> remove(String key) async { final prefs = await SharedPreferences.getInstance(); await prefs.remove(key); } }